#include<bits/stdc++.h>
using namespace std;
int a[1001][1001];
int dp[1001][2][2],n,m;
bool f(int r,int c,int x,int y,int z)
{
    if(r>1&&((a[r-1][c]^x)==(a[r][c]^y)))
    {
        return true;
    }
    if(c>1&&((a[r][c-1]^y)==(a[r][c]^y)))
    {
        return true;
    }
    if(c<m&&((a[r][c+1]^y)==(a[r][c]^y)))
    {
        return true;
    }
    if(r<n&&((a[r+1][c]^z)==(a[r][c]^y)))
    {
        return true;
    }
    return false;
}
bool check(int r,int x,int y,int z)
{
    for(int i=1;i<=m;i++)
    {
        if(!f(r,i,x,y,z))
        {
            return false;
        }
    }
    return true;
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            scanf("%d",&a[i][j]);
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=0;j<=1;j++)
        {
            for(int k=0;k<=1;k++)
            {
                dp[i][j][k]=0x7f7f7f7f;
            }
        }
    }
    dp[1][1][0]=1;
    dp[1][0][0]=0;
    for(int i=1;i<n;i++)
    {
        for(int j=0;j<=1;j++)
        {
            for(int k=0;k<=1;k++)
            {
                for(int l=0;l<=1;l++)
                {
                    if(check(i,k,j,l))
                    {
                        dp[i+1][l][j]=min(dp[i+1][l][j],dp[i][j][k]+l);
                    }
                }
            }
        }
    }
    int ans=0x7f7f7f7f;
    for(int j=0;j<=1;j++)
    {
        for(int k=0;k<=1;k++)
        {
            if(check(n,k,j,0))
            {
                ans=min(ans,dp[n][j][k]);
            }
        }
    }
    if(ans==0x7f7f7f7f)
    {
        printf("-1");
        return 0;
    }
    printf("%d",ans);
    return 0;
}
